import json
from flask import Flask, make_response, request
from pathlib import Path
from datetime import datetime, timedelta

app = Flask(__name__)
cache_dir = Path('.') / 'cache'

def get_cached_data(key):
    try:
        with open(f'{cache_dir}/{key}.json', 'r') as f:
            data = json.load(f)
            return data
    except FileNotFoundError:
        return None

def cache_data(key, data):
    if not cache_dir.exists():
        cache_dir.mkdir()
    with open(f'{cache_dir}/{key}.json', 'w') as f:
        json.dump(data, f)

def get_expiration(timestamp):
    expiration = datetime.fromisoformat(timestamp) + timedelta(days=1)
    return expiration > datetime.now()

@app.route('/', methods=['GET'])
def api_root():
    key = request.args.get('key')
    data = get_cached_data(key)
    if data:
        response = make_response(jsonify(data))
        expiration = get_expiration(data['timestamp'])
        if not expiration:
            cache_data(key, {})
            return 'No data found', 404
        response.headers['Expires'] = expiration.isoformat()
        return response
    else:
        # Call the API and cache the response
        response = make_response(jsonify({}))
        cache_data(key, response.get_json())
        return response